<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Snake</title>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body {
    min-height: 100vh;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    background: #0d1117;
    color: #e6edf3;
    font-family: system-ui, -apple-system, Segoe UI, Roboto, sans-serif;
    gap: 16px;
    padding: 20px;
  }
  h1 {
    font-size: 1.5rem;
    font-weight: 600;
    letter-spacing: 0.08em;
    color: #3fb950;
    text-transform: uppercase;
  }
  .panel {
    display: flex;
    align-items: center;
    gap: 20px;
    flex-wrap: wrap;
    justify-content: center;
  }
  #score {
    font-size: 1.15rem;
    font-variant-numeric: tabular-nums;
    background: #161b22;
    border: 1px solid #30363d;
    border-radius: 8px;
    padding: 8px 16px;
    min-width: 120px;
    text-align: center;
  }
  #score span { color: #3fb950; font-weight: 700; }
  .controls { display: flex; gap: 8px; }
  button {
    background: #21262d;
    color: #e6edf3;
    border: 1px solid #30363d;
    border-radius: 8px;
    padding: 8px 18px;
    font-size: 0.95rem;
    cursor: pointer;
    transition: background 0.15s, border-color 0.15s;
  }
  button:hover { background: #30363d; border-color: #8b949e; }
  button:active { background: #161b22; }
  #start { border-color: #238636; color: #3fb950; }
  #start:hover { background: #238636; color: #fff; }
  #pause { border-color: #9e6a03; color: #d29922; }
  #pause:hover { background: #9e6a03; color: #fff; }
  #reset { border-color: #da3633; color: #f85149; }
  #reset:hover { background: #da3633; color: #fff; }
  #snake {
    display: block;
    width: 400px;
    height: 400px;
    background: #161b22;
    border: 2px solid #30363d;
    border-radius: 12px;
    box-shadow: 0 8px 32px rgba(0,0,0,0.45);
  }
  .hint {
    font-size: 0.8rem;
    color: #8b949e;
  }
  .overlay {
    position: absolute;
    inset: 0;
    display: none;
    align-items: center;
    justify-content: center;
    background: rgba(13,17,23,0.72);
    border-radius: 12px;
    font-size: 1.4rem;
    font-weight: 700;
    color: #f85149;
    letter-spacing: 0.06em;
  }
  .board-wrap {
    position: relative;
  }
  .overlay.show { display: flex; }
</style>
</head>
<body>
  <h1>Snake</h1>
  <div class="panel">
    <div id="score">Score: <span>0</span></div>
    <div class="controls">
      <button id="start" type="button">Start</button>
      <button id="pause" type="button">Pause</button>
      <button id="reset" type="button">Reset</button>
    </div>
  </div>
  <div class="board-wrap">
    <canvas id="snake" width="400" height="400"></canvas>
    <div class="overlay" id="overlay">Game Over</div>
  </div>
  <p class="hint">Use arrow keys to steer</p>

<script>
(function () {
  const W = 20;
  const H = 20;
  const TICK_MS = 110;

  const canvas = document.getElementById('snake');
  const ctx = canvas.getContext('2d');
  const scoreEl = document.querySelector('#score span');
  const overlay = document.getElementById('overlay');

  const CELL = canvas.width / W;

  let snakeBody = [];
  let foodPos = [0, 0];
  let dir = 'right';
  let pendingDir = null;
  let isAlive = true;
  let currentScore = 0;
  let timer = null;

  const OPPOSITE = {
    up: 'down',
    down: 'up',
    left: 'right',
    right: 'left'
  };

  const DIR_DELTA = {
    up:    [0, -1],
    down:  [0,  1],
    left:  [-1, 0],
    right: [1,  0]
  };

  function cellKey(x, y) {
    return x + ',' + y;
  }

  function randomFreeCell() {
    const occupied = new Set(snakeBody.map(([x, y]) => cellKey(x, y)));
    const free = [];
    for (let y = 0; y < H; y++) {
      for (let x = 0; x < W; x++) {
        if (!occupied.has(cellKey(x, y))) free.push([x, y]);
      }
    }
    if (free.length === 0) return null;
    return free[Math.floor(Math.random() * free.length)];
  }

  function placeFoodRandom() {
    const cell = randomFreeCell();
    if (cell) foodPos = cell;
  }

  function updateScoreDisplay() {
    scoreEl.textContent = String(currentScore);
  }

  function draw() {
    const w = canvas.width;
    const h = canvas.height;

    // Background
    ctx.fillStyle = '#161b22';
    ctx.fillRect(0, 0, w, h);

    // Subtle grid
    ctx.strokeStyle = '#21262d';
    ctx.lineWidth = 1;
    for (let i = 0; i <= W; i++) {
      ctx.beginPath();
      ctx.moveTo(i * CELL + 0.5, 0);
      ctx.lineTo(i * CELL + 0.5, h);
      ctx.stroke();
    }
    for (let j = 0; j <= H; j++) {
      ctx.beginPath();
      ctx.moveTo(0, j * CELL + 0.5);
      ctx.lineTo(w, j * CELL + 0.5);
      ctx.stroke();
    }

    // Food
    const [fx, fy] = foodPos;
    const pad = CELL * 0.18;
    const fr = CELL * 0.28;
    ctx.fillStyle = '#f85149';
    ctx.beginPath();
    ctx.roundRect(fx * CELL + pad, fy * CELL + pad, CELL - pad * 2, CELL - pad * 2, fr);
    ctx.fill();
    // highlight
    ctx.fillStyle = 'rgba(255,255,255,0.25)';
    ctx.beginPath();
    ctx.arc(fx * CELL + CELL * 0.38, fy * CELL + CELL * 0.38, CELL * 0.12, 0, Math.PI * 2);
    ctx.fill();

    // Snake
    for (let i = snakeBody.length - 1; i >= 0; i--) {
      const [x, y] = snakeBody[i];
      const isHead = i === 0;
      const t = snakeBody.length <= 1 ? 1 : 1 - (i / (snakeBody.length - 1)) * 0.45;
      const g = Math.round(185 * t + 70);
      const r = Math.round(63 * t);
      const b = Math.round(80 * t);
      ctx.fillStyle = isHead ? '#56d364' : `rgb(${r},${g},${b})`;
      const sp = isHead ? CELL * 0.08 : CELL * 0.12;
      const rr = isHead ? CELL * 0.22 : CELL * 0.18;
      ctx.beginPath();
      ctx.roundRect(x * CELL + sp, y * CELL + sp, CELL - sp * 2, CELL - sp * 2, rr);
      ctx.fill();

      if (isHead) {
        // Eyes
        const eyeR = CELL * 0.08;
        let e1x, e1y, e2x, e2y;
        const cx = x * CELL + CELL / 2;
        const cy = y * CELL + CELL / 2;
        const off = CELL * 0.16;
        if (dir === 'right') {
          e1x = cx + off * 0.5; e1y = cy - off;
          e2x = cx + off * 0.5; e2y = cy + off;
        } else if (dir === 'left') {
          e1x = cx - off * 0.5; e1y = cy - off;
          e2x = cx - off * 0.5; e2y = cy + off;
        } else if (dir === 'up') {
          e1x = cx - off; e1y = cy - off * 0.5;
          e2x = cx + off; e2y = cy - off * 0.5;
        } else {
          e1x = cx - off; e1y = cy + off * 0.5;
          e2x = cx + off; e2y = cy + off * 0.5;
        }
        ctx.fillStyle = '#0d1117';
        ctx.beginPath();
        ctx.arc(e1x, e1y, eyeR, 0, Math.PI * 2);
        ctx.arc(e2x, e2y, eyeR, 0, Math.PI * 2);
        ctx.fill();
      }
    }
  }

  // Polyfill roundRect if needed
  if (!CanvasRenderingContext2D.prototype.roundRect) {
    CanvasRenderingContext2D.prototype.roundRect = function (x, y, w, h, r) {
      if (typeof r === 'number') r = [r, r, r, r];
      const [tl, tr, br, bl] = r;
      this.moveTo(x + tl, y);
      this.lineTo(x + w - tr, y);
      this.quadraticCurveTo(x + w, y, x + w, y + tr);
      this.lineTo(x + w, y + h - br);
      this.quadraticCurveTo(x + w, y + h, x + w - br, y + h);
      this.lineTo(x + bl, y + h);
      this.quadraticCurveTo(x, y + h, x, y + h - bl);
      this.lineTo(x, y + tl);
      this.quadraticCurveTo(x, y, x + tl, y);
      this.closePath();
      return this;
    };
  }

  function stopLoop() {
    if (timer !== null) {
      clearInterval(timer);
      timer = null;
    }
  }

  function startLoop() {
    stopLoop();
    timer = setInterval(() => {
      game.tick();
    }, TICK_MS);
  }

  function showOverlay(text) {
    overlay.textContent = text;
    overlay.classList.add('show');
  }

  function hideOverlay() {
    overlay.classList.remove('show');
  }

  const game = {
    w: W,
    h: H,

    reset() {
      stopLoop();
      const midY = Math.floor(H / 2);
      const midX = Math.floor(W / 2);
      // Head first, length 3, facing right
      snakeBody = [
        [midX, midY],
        [midX - 1, midY],
        [midX - 2, midY]
      ];
      dir = 'right';
      pendingDir = null;
      isAlive = true;
      currentScore = 0;
      placeFoodRandom();
      updateScoreDisplay();
      hideOverlay();
      draw();
    },

    tick() {
      if (!isAlive) return;

      if (pendingDir) {
        if (OPPOSITE[pendingDir] !== dir) {
          dir = pendingDir;
        }
        pendingDir = null;
      }

      const [dx, dy] = DIR_DELTA[dir];
      const head = snakeBody[0];
      const nx = head[0] + dx;
      const ny = head[1] + dy;

      // Wall collision
      if (nx < 0 || ny < 0 || nx >= W || ny >= H) {
        isAlive = false;
        stopLoop();
        showOverlay('Game Over');
        draw();
        return;
      }

      // Self collision (check against body; tail will move unless growing)
      const willGrow = (nx === foodPos[0] && ny === foodPos[1]);
      const bodyToCheck = willGrow ? snakeBody : snakeBody.slice(0, -1);
      for (let i = 0; i < bodyToCheck.length; i++) {
        if (bodyToCheck[i][0] === nx && bodyToCheck[i][1] === ny) {
          isAlive = false;
          stopLoop();
          showOverlay('Game Over');
          draw();
          return;
        }
      }

      snakeBody.unshift([nx, ny]);

      if (willGrow) {
        currentScore += 1;
        updateScoreDisplay();
        placeFoodRandom();
      } else {
        snakeBody.pop();
      }

      draw();
    },

    setDir(d) {
      if (d !== 'up' && d !== 'down' && d !== 'left' && d !== 'right') return;
      // Ignore 180° relative to current committed direction
      // (and also relative to already-queued turn if any)
      const base = pendingDir || dir;
      if (OPPOSITE[d] === base) return;
      if (OPPOSITE[d] === dir) return;
      pendingDir = d;
    },

    setFood(x, y) {
      foodPos = [x, y];
      draw();
    },

    snake() {
      return snakeBody.map(([x, y]) => [x, y]);
    },

    food() {
      return [foodPos[0], foodPos[1]];
    },

    alive() {
      return isAlive;
    },

    score() {
      return currentScore;
    }
  };

  window.game = game;

  // UI
  document.getElementById('start').addEventListener('click', () => {
    if (!isAlive) game.reset();
    hideOverlay();
    startLoop();
  });

  document.getElementById('pause').addEventListener('click', () => {
    stopLoop();
  });

  document.getElementById('reset').addEventListener('click', () => {
    game.reset();
  });

  window.addEventListener('keydown', (e) => {
    const map = {
      ArrowUp: 'up',
      ArrowDown: 'down',
      ArrowLeft: 'left',
      ArrowRight: 'right'
    };
    if (map[e.key]) {
      e.preventDefault();
      game.setDir(map[e.key]);
    }
  });

  // Boot
  game.reset();
})();
</script>
</body>
</html>
